code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card } from 'decantr/components';

code.example:
function ChartGrid({ charts }) {
  const { div, h3, span } = tags;

  const items = charts || [
    { title: 'Revenue Over Time', type: 'line', legends: ['Revenue', 'Expenses'] },
    { title: 'Users by Region', type: 'bar', legends: ['NA', 'EU', 'APAC'] },
    { title: 'Traffic Sources', type: 'pie', legends: ['Organic', 'Paid', 'Referral'] },
    { title: 'Engagement Trend', type: 'area', legends: ['Sessions', 'Bounce Rate'] },
  ];

  return div({ class: css('_grid _gc1 _lg:gc2 _gap4') },
    ...items.map(chart =>
      Card({ class: css('_flex _col _gap2 _p4') },
        h3({ class: css('_textsm _fontmedium') }, chart.title),
        div({ class: css('_minh[200px] _bgmuted/10 _r2 _flex _center'), 'data-chart-type': chart.type },
          span({ class: css('_fgmuted _textsm') }, `[${chart.type} chart placeholder]`)
        ),
        div({ class: css('_flex _gap2 _textxs _fgmuted') },
          ...chart.legends.map(l =>
            div({ class: css('_flex _aic _gap1') },
              div({ class: css('_w2 _h2 _rfull _bgprimary') }),
              span({}, l)
            )
          )
        )
      )
    )
  );
}

